// ── Export ───────────────────────────────────────────────────────────────────
export default function AdminPage({ onBack }) {
  const [authed, setAuthed] = useState(() => sessionStorage.getItem('_ukr_admin') === '1');
  const handleLogout = () => { sessionStorage.removeItem('_ukr_admin'); setAuthed(false); };

  return (
    <div>
      <div style={{ background: '#0057b7', padding: '12px 24px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <span style={{ color: '#ffd700', fontWeight: 700, fontSize: 18 }}>🏛 Украдені скарби — Admin</span>
        <button style={{ ...styles.btnGhost, color: '#ffd700', borderColor: '#ffd700' }} onClick={onBack}>← Back</button>
      </div>
      {authed
        ? <AdminDashboard onLogout={handleLogout} />
        : <AdminLogin onAuth={() => setAuthed(true)} />
      }
    </div>
  );
}
