// Transliteration map: English to Russian/Ukrainian
function transliterateToRussian(text) {
  const map = {
    'a': 'а', 'b': 'б', 'v': 'в', 'g': 'г', 'd': 'д', 'e': 'е', 'yo': 'ё', 'zh': 'ж', 
    'z': 'з', 'i': 'и', 'y': 'й', 'k': 'к', 'l': 'л', 'm': 'м', 'n': 'н', 'o': 'о', 
    'p': 'п', 'r': 'р', 's': 'с', 't': 'т', 'u': 'у', 'f': 'ф', 'h': 'х', 'kh': 'х',
    'ts': 'ц', 'ch': 'ч', 'sh': 'ш', 'shch': 'щ', 'sch': 'щ', 'ie': 'ъ', 'yi': 'ы', 
    'iy': 'ий', 'yu': 'ю', 'ya': 'я', 'ye': 'є', 
    'w': 'в', 'x': 'кс', 'j': 'й', 'c': 'к', 'q': 'к'
  };
  
  let result = text.toLowerCase();
  // Replace longer sequences first
  const sortedKeys = Object.keys(map).sort((a, b) => b.length - a.length);
  for (const key of sortedKeys) {
    result = result.replace(new RegExp(key, 'g'), map[key]);
  }
  return result;
}

